function IfThisThenThat() {
  const [name, setName] = React.useState('My Rule');
  const [triggerType, setTriggerType] = React.useState('cron');
  const [triggerArg, setTriggerArg] = React.useState('0 9 * * *');
  const [actionType, setActionType] = React.useState('agent');
  const [actionArg, setActionArg] = React.useState('REPLACE_WITH_ACTION');
  const [rules, setRules] = React.useState(()=>{ try { return JSON.parse(localStorage.getItem('titan-ifttt-rules')||'[]'); } catch { return []; } });
  const [busy, setBusy] = React.useState(false);
  const save = async () => {
    setBusy(true);
    const rule = { id: Date.now()+'', name, triggerType, triggerArg, actionType, actionArg, enabled:true };
    const next = [...rules, rule];
    setRules(next); localStorage.setItem('titan-ifttt-rules', JSON.stringify(next));
    try { await titan.api.call('/api/event-triggers', { method: 'POST', body: rule }); } catch {}
    setBusy(false);
  };
  const toggle = (id) => { const next = rules.map(r=>r.id===id?{...r,enabled:!r.enabled}:r); setRules(next); localStorage.setItem('titan-ifttt-rules', JSON.stringify(next)); };
  const remove = (id) => { const next = rules.filter(r=>r.id!==id); setRules(next); localStorage.setItem('titan-ifttt-rules', JSON.stringify(next)); };
  return (
    <div style={{padding:14,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',gap:8}}>
      <input value={name} onChange={e=>setName(e.target.value)} placeholder="Rule name" style={{padding:'6px 10px',border:'1px solid #ccc',borderRadius:6,fontSize:14,fontWeight:600}}/>
      <div style={{display:'flex',gap:6,alignItems:'center'}}>
        <span style={{fontSize:12,fontWeight:600,color:'#FF9500',width:30}}>IF</span>
        <select value={triggerType} onChange={e=>setTriggerType(e.target.value)} style={{padding:'6px',border:'1px solid #ccc',borderRadius:6,fontSize:12}}>
          <option value="cron">cron</option><option value="webhook">webhook</option><option value="sensor">sensor</option><option value="price">price</option>
        </select>
        <input value={triggerArg} onChange={e=>setTriggerArg(e.target.value)} style={{flex:1,padding:'6px 8px',border:'1px solid #ccc',borderRadius:6,fontSize:12,fontFamily:'monospace'}}/>
      </div>
      <div style={{display:'flex',gap:6,alignItems:'center'}}>
        <span style={{fontSize:12,fontWeight:600,color:'#34C759',width:30}}>THEN</span>
        <select value={actionType} onChange={e=>setActionType(e.target.value)} style={{padding:'6px',border:'1px solid #ccc',borderRadius:6,fontSize:12}}>
          <option value="agent">ask agent</option><option value="skill">run skill</option><option value="api">api call</option><option value="notify">notify</option>
        </select>
        <input value={actionArg} onChange={e=>setActionArg(e.target.value)} style={{flex:1,padding:'6px 8px',border:'1px solid #ccc',borderRadius:6,fontSize:12}}/>
      </div>
      <button onClick={save} disabled={busy} style={{padding:'8px',border:'none',borderRadius:6,background:'#007AFF',color:'#fff',fontWeight:600,cursor:'pointer'}}>{busy?'Saving…':'+ Save Rule'}</button>
      <div style={{flex:1,overflow:'auto',marginTop:6}}>
        {rules.map(r => (
          <div key={r.id} style={{padding:8,borderBottom:'1px solid #f0f0f0',display:'flex',gap:8,alignItems:'center'}}>
            <input type="checkbox" checked={r.enabled} onChange={()=>toggle(r.id)}/>
            <div style={{flex:1,fontSize:12}}>
              <div style={{fontWeight:600}}>{r.name}</div>
              <div style={{color:'#888'}}>IF {r.triggerType}: <code>{r.triggerArg}</code> → {r.actionType}: {r.actionArg}</div>
            </div>
            <button onClick={()=>remove(r.id)} style={{padding:'2px 8px',border:'1px solid #ddd',background:'#fff',borderRadius:4,cursor:'pointer'}}>✕</button>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<IfThisThenThat/>);
